patch:
diff --git a/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp b/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
index 0200525a718d..bd56c373c931 100644
--- a/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
+++ b/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
@@ -7315,6 +7315,14 @@ static bool planContainsAdditionalSimplifications(VPlan &Plan,
     return any_of(*BB, [&SeenInstrs, &CostCtx](Instruction &I) {
       if (isa<PHINode>(&I))
         return false;
+      // Check for constant icmp instructions which can be simplified differently
+      // between cost models.
+      if (auto *ICmp = dyn_cast<ICmpInst>(&I)) {
+        if (isa<Constant>(ICmp->getOperand(0)) && isa<Constant>(ICmp->getOperand(1))) {
+          // Constant icmp operations can be simplified and may cause cost model differences.
+          return true;
+        }
+      }
       return !SeenInstrs.contains(&I) && !CostCtx.skipCostComputation(&I, true);
     });
   });

